window.bookSummaryJSON = "<p>The monster that is <i>Haunted Reels</i> has returned, and now no one is safe. Featuring twenty-four brand-new, never-before-published stories by a mix of Hollywood legends and rising film-industry stars, <i>Haunted Reels 2</i> continues the menace its brooding predecessor started, only this time it has a grudge. Beware the murderous vandals, maniacal crackpots, and diabolically possessed contained within this book, for once you let them loose, there’s no telling what they’ll do next.</p>"; 
